import React, { useState, useEffect } from 'react';
import {
  CreditCardIcon,
  CheckCircleIcon,
  XCircleIcon,
  CalendarIcon,
  CurrencyRupeeIcon,
  ArrowUpRightIcon
} from '@heroicons/react/24/outline';
import { workerAPI } from '../services/api';
import toast from 'react-hot-toast';

const WeeklyPremium = () => {
  const [premiumStatus, setPremiumStatus] = useState(null);
  const [loading, setLoading] = useState(true);
  const [paymentLoading, setPaymentLoading] = useState(false);
  const [showPaymentForm, setShowPaymentForm] = useState(false);
  const [paymentMethod, setPaymentMethod] = useState('upi');
  const [transactionId, setTransactionId] = useState('');

  useEffect(() => {
    fetchPremiumStatus();
    // Refresh every 60 seconds
    const interval = setInterval(fetchPremiumStatus, 60000);
    return () => clearInterval(interval);
  }, []);

  const fetchPremiumStatus = async () => {
    try {
      const response = await workerAPI.getPremiumStatus();
      setPremiumStatus(response.data.data);
    } catch (error) {
      console.error('Error fetching premium status:', error);
      toast.error('Failed to fetch premium status');
    } finally {
      setLoading(false);
    }
  };

  const handlePaymentSubmit = async (e) => {
    e.preventDefault();
    
    if (!transactionId.trim()) {
      toast.error('Please enter transaction ID');
      return;
    }

    try {
      setPaymentLoading(true);
      
      const response = await workerAPI.payWeeklyPremium({
        paymentMethod,
        transactionId,
        amount: premiumStatus.weeklyAmount
      });

      if (response.data.success) {
        toast.success('Premium paid successfully!');
        setShowPaymentForm(false);
        setTransactionId('');
        setPaymentMethod('upi');
        fetchPremiumStatus();
      }
    } catch (error) {
      console.error('Payment error:', error);
      toast.error(error.response?.data?.message || 'Payment failed');
    } finally {
      setPaymentLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  const canClaimInsurance = premiumStatus?.canClaimInsurance;

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Weekly Premium</h1>
        <p className="text-gray-600">Manage your weekly insurance premium payments</p>
      </div>

      {/* Premium Status Card */}
      <div className={`card border-l-4 ${canClaimInsurance ? 'border-l-green-600' : 'border-l-red-600'}`}>
        <div className="card-header">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-semibold text-gray-900">Current Status</h3>
            {canClaimInsurance ? (
              <div className="flex items-center bg-green-100 text-green-800 px-4 py-2 rounded-full">
                <CheckCircleIcon className="h-5 w-5 mr-2" />
                <span className="font-medium">Premium Active</span>
              </div>
            ) : (
              <div className="flex items-center bg-red-100 text-red-800 px-4 py-2 rounded-full">
                <XCircleIcon className="h-5 w-5 mr-2" />
                <span className="font-medium">Premium Overdue</span>
              </div>
            )}
          </div>
        </div>

        <div className="card-content">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {/* Weekly Amount */}
            <div>
              <div className="flex items-center text-gray-600 mb-2">
                <CurrencyRupeeIcon className="h-5 w-5 mr-2" />
                <span className="text-sm">Weekly Premium</span>
              </div>
              <p className="text-3xl font-bold text-gray-900">₹{premiumStatus?.weeklyAmount || 0}</p>
            </div>

            {/* Current Week Status */}
            <div>
              <div className="flex items-center text-gray-600 mb-2">
                <CheckCircleIcon className="h-5 w-5 mr-2" />
                <span className="text-sm">This Week</span>
              </div>
              <p className={`text-lg font-semibold ${premiumStatus?.currentWeekPaid ? 'text-green-600' : 'text-red-600'}`}>
                {premiumStatus?.currentWeekPaid ? 'Paid' : 'Due'}
              </p>
            </div>

            {/* Last Payment */}
            <div>
              <div className="flex items-center text-gray-600 mb-2">
                <CalendarIcon className="h-5 w-5 mr-2" />
                <span className="text-sm">Last Payment</span>
              </div>
              <p className="text-lg font-semibold text-gray-900">
                {premiumStatus?.lastPaymentDate
                  ? new Date(premiumStatus.lastPaymentDate).toLocaleDateString('en-IN')
                  : 'Never'}
              </p>
            </div>

            {/* Next Due */}
            <div>
              <div className="flex items-center text-gray-600 mb-2">
                <ArrowUpRightIcon className="h-5 w-5 mr-2" />
                <span className="text-sm">Next Due</span>
              </div>
              <p className="text-lg font-semibold text-gray-900">
                {premiumStatus?.nextPaymentDue
                  ? new Date(premiumStatus.nextPaymentDue).toLocaleDateString('en-IN')
                  : 'Not set'}
              </p>
            </div>
          </div>
        </div>

        {/* Insurance Coverage Info */}
        <div className={`p-4 rounded-lg ${canClaimInsurance ? 'bg-green-50' : 'bg-red-50'}`}>
          {canClaimInsurance ? (
            <div className="flex items-start">
              <CheckCircleIcon className="h-6 w-6 text-green-600 mr-3 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-semibold text-green-900">Insurance Coverage Active</p>
                <p className="text-sm text-green-800 mt-1">
                  You can file insurance claims for incidents that occur during your active working hours.
                </p>
              </div>
            </div>
          ) : (
            <div className="flex items-start">
              <XCircleIcon className="h-6 w-6 text-red-600 mr-3 flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-semibold text-red-900">Insurance Coverage Disabled</p>
                <p className="text-sm text-red-800 mt-1">
                  Your insurance coverage is disabled until this week's premium is paid. You won't be able to file claims until payment is received.
                </p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Payment Form */}
      {!premiumStatus?.currentWeekPaid && !showPaymentForm ? (
        <button
          onClick={() => setShowPaymentForm(true)}
          className="btn-primary flex items-center"
        >
          <CreditCardIcon className="h-5 w-5 mr-2" />
          Pay Weekly Premium
        </button>
      ) : null}

      {showPaymentForm && (
        <div className="card">
          <div className="card-header">
            <h3 className="text-lg font-semibold text-gray-900">Pay Premium</h3>
          </div>
          
          <form onSubmit={handlePaymentSubmit} className="card-content space-y-4">
            {/* Payment Method */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Payment Method
              </label>
              <select
                value={paymentMethod}
                onChange={(e) => setPaymentMethod(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent"
              >
                <option value="upi">UPI</option>
                <option value="bank_transfer">Bank Transfer</option>
                <option value="card">Debit Card</option>
                <option value="wallet">Wallet</option>
              </select>
            </div>

            {/* Amount */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Amount to Pay
              </label>
              <div className="relative">
                <span className="absolute left-4 top-2.5 text-gray-500">₹</span>
                <input
                  type="text"
                  disabled
                  value={premiumStatus?.weeklyAmount || 0}
                  className="w-full pl-8 pr-4 py-2 border border-gray-300 rounded-lg bg-gray-50 text-gray-600"
                />
              </div>
            </div>

            {/* Transaction ID */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Transaction ID / Reference Number
              </label>
              <input
                type="text"
                value={transactionId}
                onChange={(e) => setTransactionId(e.target.value)}
                placeholder="Enter your transaction ID"
                required
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent"
              />
              <p className="text-xs text-gray-500 mt-1">
                This will be used to verify your payment
              </p>
            </div>

            {/* Instructions */}
            <div className="bg-blue-50 p-4 rounded-lg">
              <p className="text-sm text-gray-700 font-medium mb-2">Payment Instructions:</p>
              <ol className="text-sm text-gray-600 space-y-1 list-decimal list-inside">
                <li>Make a payment of ₹{premiumStatus?.weeklyAmount || 0} using your preferred method</li>
                <li>Copy your transaction ID from the payment confirmation</li>
                <li>Enter the transaction ID above and submit</li>
              </ol>
            </div>

            {/* Submit Buttons */}
            <div className="flex gap-3 pt-4">
              <button
                type="button"
                onClick={() => {
                  setShowPaymentForm(false);
                  setTransactionId('');
                }}
                className="btn-outline flex-1"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={paymentLoading}
                className="btn-primary flex-1 flex items-center justify-center"
              >
                {paymentLoading ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                    Processing...
                  </>
                ) : (
                  <>
                    <CreditCardIcon className="h-5 w-5 mr-2" />
                    Submit Payment
                  </>
                )}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Payment History */}
      <div className="card">
        <div className="card-header">
          <h3 className="text-lg font-semibold text-gray-900">Payment History</h3>
        </div>

        <div className="card-content">
          {premiumStatus?.paymentHistory && premiumStatus.paymentHistory.length > 0 ? (
            <div className="space-y-3">
              {premiumStatus.paymentHistory.map((payment, index) => (
                <div key={index} className="flex items-center justify-between p-3 bg-gray-50 rounded">
                  <div>
                    <p className="font-medium text-gray-900">{payment.weekNumber}</p>
                    <p className="text-sm text-gray-600">
                      {new Date(payment.paymentDate).toLocaleDateString('en-IN')}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-semibold text-gray-900">₹{payment.amount}</p>
                    <div className="flex items-center justify-end mt-1">
                      {payment.status === 'paid' ? (
                        <>
                          <CheckCircleIcon className="h-4 w-4 text-green-600 mr-1" />
                          <span className="text-sm text-green-600">Paid</span>
                        </>
                      ) : (
                        <>
                          <XCircleIcon className="h-4 w-4 text-red-600 mr-1" />
                          <span className="text-sm text-red-600">{payment.status}</span>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-center text-gray-500 py-4">No payment history yet</p>
          )}
        </div>
      </div>

      {/* Summary */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="card">
          <div className="card-content">
            <p className="text-sm text-gray-600 mb-1">Total Paid</p>
            <p className="text-2xl font-bold text-gray-900">₹{premiumStatus?.totalPaid || 0}</p>
          </div>
        </div>
        <div className="card">
          <div className="card-content">
            <p className="text-sm text-gray-600 mb-1">Missed Payments</p>
            <p className={`text-2xl font-bold ${premiumStatus?.missedPayments ? 'text-red-600' : 'text-green-600'}`}>
              {premiumStatus?.missedPayments || 0}
            </p>
          </div>
        </div>
        <div className="card">
          <div className="card-content">
            <p className="text-sm text-gray-600 mb-1">Premium Status</p>
            <p className={`text-lg font-bold ${canClaimInsurance ? 'text-green-600' : 'text-red-600'}`}>
              {canClaimInsurance ? 'Active' : 'Inactive'}
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WeeklyPremium;
